125→    /*
126→     * returns the passed string formatted for use with our API - see sanitize_title_with_dashes
127→     * https://git.io/JqUEP
128→     * http://stackoverflow.com/a/1612015/1673548
129→     */
130→    public static String sanitizeWithDashes(final String title) {
131→        if (title == null) {
132→            return "";
133→        }
134→
135→        String trimmedTitle = title.trim();
136→        if (isValidUrlEncodedString(trimmedTitle)) {
137→            return trimmedTitle;
138→        } else {
139→            return trimmedTitle
140→                        .replaceAll("&[^\\s]*;", "") // remove html entities
141→                        .replaceAll("[\\.\\s]+", "-") // replace periods and whitespace with a dash
142→                        .replaceAll("[^\\p{L}\\p{Nd}\\-]+",
143→                                "") // remove remaining non-alphanum/non-dash chars (Unicode aware)
144→                        .replaceAll("--", "-"); // reduce double dashes potentially added above
145→        }
146→    }
